query:
-- Add columns to fitasty_products table
ALTER TABLE fitasty_products ADD COLUMN IF NOT EXISTS net_weight_g DECIMAL(6,1) COMMENT 'Net weight in grams for per100g calculation';

-- Add columns to food_log_items table
ALTER TABLE food_log_items ADD COLUMN IF NOT EXISTS source VARCHAR(50) COMMENT 'fitasty, usda, off, manual';
ALTER TABLE food_log_items ADD COLUMN IF NOT EXISTS external_id VARCHAR(255) COMMENT 'fitasty_product_id, usda fdcId, or off code';
ALTER TABLE food_log_items ADD COLUMN IF NOT EXISTS grams DECIMAL(6,1) COMMENT 'Quantity in grams';
ALTER TABLE food_log_items ADD COLUMN IF NOT EXISTS per100g_kcal DECIMAL(8,1) COMMENT 'Kcal per 100g used for calculation';
ALTER TABLE food_log_items ADD COLUMN IF NOT EXISTS per100g_protein DECIMAL(6,1) COMMENT 'Protein per 100g';
ALTER TABLE food_log_items ADD COLUMN IF NOT EXISTS per100g_carbs DECIMAL(6,1) COMMENT 'Carbs per 100g';
ALTER TABLE food_log_items ADD COLUMN IF NOT EXISTS per100g_fat DECIMAL(6,1) COMMENT 'Fat per 100g';
ALTER TABLE food_log_items ADD COLUMN IF NOT EXISTS is_autofilled TINYINT DEFAULT 0 COMMENT '1 = auto-filled, 0 = manual';

-- Add columns to exercises table
ALTER TABLE exercises ADD COLUMN IF NOT EXISTS source VARCHAR(50) DEFAULT 'manual' COMMENT 'auto or manual';
ALTER TABLE exercises ADD COLUMN IF NOT EXISTS met_used DECIMAL(4,1) COMMENT 'MET value used for calculation';
ALTER TABLE exercises ADD COLUMN IF NOT EXISTS weight_used_kg DECIMAL(5,1) COMMENT 'Weight used for calorie calculation';

-- Create general_food_cache table
CREATE TABLE IF NOT EXISTS general_food_cache (
  id INT AUTO_INCREMENT NOT NULL PRIMARY KEY,
  source ENUM('usda','off') NOT NULL COMMENT 'usda or off',
  external_id VARCHAR(255) NOT NULL COMMENT 'USDA fdcId or OFF code',
  display_name VARCHAR(255) NOT NULL,
  brand VARCHAR(255),
  kcal_per_100g DECIMAL(8,1),
  protein_g_per_100g DECIMAL(6,1),
  carbs_g_per_100g DECIMAL(6,1),
  fat_g_per_100g DECIMAL(6,1),
  raw_json TEXT COMMENT 'Raw API response for debugging',
  createdAt TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP,
  updatedAt TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  UNIQUE KEY unique_source_id (source, external_id)
);

